};

struct ObserverCollectionSummary {
    std::size_t totalObservers;
    bool containsDirectObserver;
    bool containsTransitiveObserver;
};

ObserverCollectionSummary test_observer_collection() {
    // 1. Create two NamedObserverNode instances with unique names
    NamedObserverNode directNode("direct_node");
    NamedObserverNode transitiveNode("transitive_node");

    // 2. Get the singleton ObserverGraph instance
    auto& observerGraph = reaction::ObserverGraph::getInstance();

    // 3. Register both nodes using ObserverGraph::addNode()
    observerGraph.addNode(directNode.shared_from_this());
    observerGraph.addNode(transitiveNode.shared_from_this());

    // 4. Set up direct observer relationship using ObserverGraph::addObserver()
    observerGraph.addObserver(directNode.shared_from_this(), transitiveNode.shared_from_this());

    // 5. Set up transitive observer relationship by adding the transitive node as an observer of the direct node
