ResourceAtomicResult test_resource_atomic(int initialValue, int delta) {
    // 1. Create a Resource instance with initial value
    reaction::Resource<int> resource(initialValue);

    // 2. Create a boolean variable to track if operation reported change
    bool changeReported = false;

    // 3. Use atomicOperation method to add delta to the value
    // The lambda function takes the current value and returns the new value
    // It also returns a boolean indicating if the value changed
    resource.atomicOperation([&changeReported, delta](int currentValue) -> int {
        int newValue = currentValue + delta;
        changeReported = (newValue != currentValue); // Track if value actually changed
        return newValue;
    });

    // 4. Use getValue method to retrieve the final value
    int finalValue = resource.getValue();

    // 5. Return ResourceAtomicResult with final value and change status
    return ResourceAtomicResult{finalValue, changeReported};
}

